def gen(rng, size):
    n = max(2, min(size, 200000))
    nums = []
    val = 0
    while len(nums) < n:
        run_len = rng.randint(1, 6)
        for _ in range(run_len):
            if len(nums) >= n:
                break
            nums.append(val)
            val += rng.randint(1, 5)
        val -= rng.randint(0, 10)
    return [nums]

