class Solution:
    def maxIncreasingSubarrays(self, nums):
        n = len(nums)
        def strictly_increasing(start, length):
            for i in range(start, start + length - 1):
                if nums[i] >= nums[i + 1]:
                    return False
            return True
        best = 0
        for k in range(n // 2, 0, -1):
            found = False
            for a in range(0, n - 2 * k + 1):
                if strictly_increasing(a, k) and strictly_increasing(a + k, k):
                    found = True
                    break
            if found:
                best = k
                break
        return best

