class Solution:
    def maxIncreasingSubarrays(self, nums):
        n = len(nums)
        inc = [1] * n
        for i in range(1, n):
            if nums[i] > nums[i - 1]:
                inc[i] = inc[i - 1] + 1
        asc = [1] * n
        for i in range(n - 2, -1, -1):
            if nums[i] < nums[i + 1]:
                asc[i] = asc[i + 1] + 1
        best = 0
        for i in range(1, n):
            cand = min(inc[i - 1], asc[i])
            if cand > best:
                best = cand
        return best

