var maxIncreasingSubarrays = function(nums) {
    const n = nums.length;
    const inc = new Array(n).fill(1);
    for (let i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1]) inc[i] = inc[i - 1] + 1;
    }
    const asc = new Array(n).fill(1);
    for (let i = n - 2; i >= 0; i--) {
        if (nums[i] < nums[i + 1]) asc[i] = asc[i + 1] + 1;
    }
    let best = 0;
    for (let i = 1; i < n; i++) {
        const cand = Math.min(inc[i - 1], asc[i]);
        if (cand > best) best = cand;
    }
    return best;
};
